-- moodyds54  json_md5=5f3d23d58bafa53da2566bd03a7e4667  json_len=12288
WITH ok AS (SELECT j FROM (SELECT $moodyds54${"id":"moodyds54","name":"Moody Decksaloon 54","builder":"Moody (HanseYachts) · Germany","designer":"Bill Dixon (deck saloon/styling) · Judel/Vrolijk (Hanse 575/588 hull)","color":"#3b5a76","years":"2014–present","material":"GRP (balsa-cored)","category":"Deck-saloon & pilothouse","cockpit_type":"Single-level deck saloon","loa":"56'3\" (17.17 m)","lwl":"51'0\" (15.55 m)","beam":"17'0\" (5.19 m)","draft_min":"7'3\" (2.22 m shoal)","draft_max":"8'8\" (2.69 m deep)","displacement":"~24,500 kg / 54,000 lb","ballast":"~6,700 kg","ballast_ratio":"~27%","sail_area":"142 m² / 1,528 ft²","air_draft":"~25 m / 82'","engine":"Volvo D3 ~150 hp","drive":"Shaft","cabins":"3–4 cabins / 3 heads","keel":"Fin keel with bulb + spade rudder; deep or shoal cast-iron keel; bow & stern thrusters standard","cockpit":"Single-level deck saloon: cockpit and main saloon on ONE level via sliding glass doors; inside steering/nav; retractable bimini","fuel":"522 L / 138 gal","water":"790 L / 209 gal","loa_n":17.17,"lwl_ft":51,"beam_ft":17.03,"disp_lb":54000,"draft_min_n":2.22,"sad":"~15–17","dl":"~180","fuel_n":522,"water_n":790,"engine_hp":150,"price_min_usd":700000,"price_max_usd":950000,"budget":"fit","budget_n":1,"best_for":"The cruising couple who want a catamaran-style, single-level, glass-walled bluewater monohull where dogs and a less-mobile crew never face a companionway ladder — and who will plan passages around weather rather than punch through it.","protection_text":"Exceptional, and the boat's \"winning hand.\" The cockpit shares one level with the saloon via sliding glass doors; you can stand a watch from the inside helm/nav seat in \"complete protection and all-round visibility\" (Yachting World), running the autopilot from a wireless remote (owner Adam Sutton). Substantial bulwarks and inboard/outboard handrails make the side decks \"the most secure we've seen\" (BOTY judges).","rig":"Fractional sloop on a double-spreader Seldén spar; standard solent/twin-furler setup plus a self-tending staysail; in-mast furling main (with vertical battens) common; reaching Yankee and gennaker options.","handling_text":"Strong — a self-tacking staysail/jib, in-mast furling main and furling headsails mean almost no foredeck work; all lines led aft to Lewmar winches at the helms; electric winches and electric/hydraulic furling available; bow + stern thrusters for two-handed docking.","engine_workshop":"Engine under the saloon/cockpit sole; large under-sole and lazarette spaces give good machinery access, but the integrated \"apartment afloat\" fit-out means it's an engine-behind-panels yacht more than a workshop boat. The big lazarette/garage is the most workshop-capable space.","systems":"CZone digital switching is the electrical hub; typically a genset, A/C/heating, watermaker, lithium/large house bank and full electronics; electric galley appliances throughout (a large power budget).","storage_text":"Abundant for a couple — high topsides create voluminous lower-deck stowage, deep lockers, and a big lazarette/garage aft (dinghy/toys/spares). The single-level layout frees floor area for living.","range_text":"~700–1,000+ nm motoring (fuel-dependent); moderate fuel for the longest legs, so plan fuel/jerry cans plus a watermaker.","accommodation":"The headline advantage: cockpit and main saloon are on ONE level via sliding glass doors — like a catamaran — so dogs and a less-mobile crew move between the sheltered saloon and the cockpit with NO companionway ladder, and reach the fold-down transom platform with minimal vertical movement. Only the sleeping cabins (and optionally the galley) need stairs.","high_lat_text":"Very good — an enclosed, all-round-visibility deck saloon lets a short-handed crew keep watch and steer without exposure in cold, wet weather. Cat A hull, secure side decks. Honest watch-outs: extensive glazing means real heat loss and condensation (Yachting World saw fogging in cold trials and noted blinds were unavailable at test), and a large systems/heating load.","tropical_text":"Excellent — the retractable bimini and shaded saloon give superb sun protection; sliding doors + hatches give cross-ventilation; A/C typical; the swim platform and one-level living are perfect for anchorages. One owner did flag the glass saloon getting hot in the Med without A/C.","price_text":"$700k–$950k (used)","price_new":"New base ~$784,500 (US, 2017) / €549,000 (EU, 2015); well-equipped ~$1.1M","price_used":"Used ~$700k–$950k (2014–2019); newer/loaded examples toward $1M+","budget_text":"A clean used 2014–2019 DS54 fits under $1M (a 2019 example listed at US$850k); new is above budget. The single-level layout is its killer feature for this crew. It rides the same Judel/Vrolijk hull as the cheaper Hanse 575/588 — but those trade the protected saloon for an open aft cockpit.","notable":"No single famous campaign, but a DS54 (\"Mojeka\") sailed the 2015 ARC+ — 3,125 nm Las Palmas→Cape Verdes→St Lucia in 12 days, finishing in the top four of its group — and owners cruise them transatlantic and in the Med/Caribbean. It is Moody's flagship long-range deck-saloon model.","scores":{"protection":5,"handling":4.5,"dogs":5,"workshop":3,"storage":4.5,"tankage":3.5,"highlat":4,"tropical":4.5,"budget":4},"tags":["Single-level living","No companionway ladder","Inside steering","Best for dogs"],"fun":["A DS54 named \"Mojeka\" crossed the Atlantic in the 2015 ARC+ — 3,125 nm in 12 days, finishing top-four in its group, furling sail \"at the touch of a button\" through a storm front.","The deck-saloon concept revived a near-200-year-old British marque under German (Hanse) ownership — a Judel/Vrolijk hull (shared with the Hanse 575/588) wearing a Bill Dixon \"lifestyle\" deck.","BOTY judges singled out \"the most secure side decks we've seen\" and the genuinely livable one-level layout; a hydraulically folding transom becomes a beach-club swim platform."],"price_examples":["2019 \"Harmony\" — US$850,000 (Berthon, Wickford RI)","2016 Moody DS54 — US$949,000 (IVT Yacht Sales, San Diego)","2014 — ~€700,000 (Union Yachts, Italy); 2015 ~€735,000 (De Valk)"],"sources":[{"name":"Moody (HanseYachts) — official","url":"https://moody-yachts.com/gb/sailing-yachts/moody-decksaloon-54/"},{"name":"Specs — Boat-Specs (deep draft)","url":"https://www.boat-specs.com/sailing/sailboats/moody/moody-54-ds-deep-draft"},{"name":"Boat test (heavy-weather candour) — Yachting World","url":"https://www.yachtingworld.com/reviews/boat-tests/moody-54ds-boat-test"},{"name":"Boat review (two-up, inside steering) — SAIL","url":"https://sailmagazine.com/boats/boat-review-moody-ds54/"},{"name":"Review (Judel/Vrolijk hull, layup) — Cruising World","url":"https://www.cruisingworld.com/moody-ds-54-boat-review/"},{"name":"\"Sail around the world\" test — Blue Water Sailing","url":"https://www.bwsailing.com/bw/moody-deck-saloon-54/"},{"name":"ARC+ 2015 crossing — DS54 \"Mojeka\"","url":"http://www.yachting-pleasure.com/state-of-the-art-bluewater-yacht-moody-ds54-in-the-top-four-at-arc/"},{"name":"Owner experiences — Moody Owners Information Exchange","url":"https://www.moodyowners.info/threads/moody-ds-41-45-54-owner-experience-advice.20166/"}],"youtube":[{"name":"Moody yard — official guided tour","url":"https://www.youtube.com/watch?v=FjPT70UhfVk","note":"Builder walkthrough"},{"name":"IVT 2016 DS54 walkthrough","url":"https://www.youtube.com/watch?v=bHMoTyA1jHY","note":"Detailed brokerage tour"},{"name":"2021 DS54 \"Easy\" owner walkthrough","url":"https://www.youtube.com/watch?v=fjtgjp9Zbvs","note":"Owner's-eye tour"},{"name":"Moody DS54 official","url":"https://www.youtube.com/watch?v=JHk0v__4nSU","note":"Builder feature"}],"pros":["Single-level saloon-to-cockpit living with sliding doors — outstanding for two dogs and a smaller/less-strong crew (no ladder, eye-level views, easy boarding).","Protected, heated inside steering/nav station with panoramic visibility — ideal for cold high-latitude watchkeeping.","Genuinely short-handed: self-tacking staysail, furling everything, all lines to the helm, bow+stern thrusters.","Huge, secure side decks and bulwarks; a very protected cockpit with retractable bimini for chill and sun alike.","Big lower-deck volume and a lazarette garage for storage, spares, dinghy and toys."],"cons":["Plan passages around weather: in a Force 7 and steep seas testers reported slamming and needing the engine to keep her tracking — \"owners will need to plan passages carefully\" (Yachting World).","Tall and \"a lot of boat to manage\": heeled, the raised saloon leaves \"hard to find any bracing,\" and \"a rolling sea quickly makes you realise how high up you are.\"","Moderate fuel tankage (~138 gal) limits motoring range for the longest crossings — plan fuel/jerry cans plus a watermaker.","Massive glazing means heat loss, condensation and big A/C/heating loads; insulation and a strong heater are mandatory for Patagonia.","Systems-heavy \"apartment afloat\" with electric galley and digital switching — more to maintain and a large power budget far from support.","8'8\" deep keel (shoal still 7'5\") limits gunkholing; high windage from topsides loads the helm and complicates close-quarters handling."],"awards":[],"endorsements":[{"who":"Yachting World (Toby Hodges)","note":"\"The ability to stand a watch here in complete protection and all-round visibility is the Moody's winning hand\" — though testers reported slamming and needing the engine to track in a Force 7.","url":"https://www.yachtingworld.com/reviews/boat-tests/moody-54ds-boat-test"},{"who":"SAIL (Zuzana Prochazka)","note":"\"Despite its large sail area and a displacement of over 53,000 lb, the Moody DS54 is remarkably easy to sail with just two\"; inside steering means watch-standers \"don't have to leave the comfort of the interior on long passages.\"","url":"https://sailmagazine.com/boats/boat-review-moody-ds54/"},{"who":"Blue Water Sailing (George Day)","note":"\"This is a boat that you could easily sail around the world and I'd be quite happy to give it a try\" — 42° to the true wind, tacking in just over 80°.","url":"https://www.bwsailing.com/bw/moody-deck-saloon-54/"}],"badge":"Expert-reviewed","own":{"mastStep":"Keel-stepped (tapered Seldén alloy)","keelRudder":"Bolted-on lead keel (shoal/deep) · single deep spade rudder · balsa-cored infused hull + carbon-reinforced grid","complexity":"High — electric Lewmar winches (trim from the helm), drop-down bow & stern thrusters with joystick, twin-helm steering, big deck-saloon glazing, a feature-rich production fit-out.","maintain":"Lower–Moderate — hardware is mainstream and dealer-supported (a plus), but the density of electric/hydraulic systems and the complex deck-saloon structure favour dealer/yard servicing for many tasks.","partsText":"Good — built by HanseYachts AG (Germany), a large operating production builder; shares hardware with the Hanse range (good commonality + a wide European dealer network). Volvo engine. (HanseYachts' corporate finances have been volatile — note, but parts risk is far lower than the niche builders.)","problems":"No widespread documented DS54 fault pattern; reviews largely positive (the single spade rudder was \"well up to the job\"). Considerations: a single spade rudder is less grounding-tolerant; the large saloon windows are an inherent heavy-weather exposure; condensation/fogging on the big glazing in cold weather; many electrically-actuated systems are potential maintenance points.","sentiment":"Praised for close-winded performance for a big cruiser, helm-controlled electric trimming, safe single-level living and the deck-saloon 'superyacht' feel and visibility.","communities":[{"name":"Moody Owners Information Exchange","url":"https://www.moodyowners.info/threads/moody-ds-41-45-54-owner-experience-advice.20166/"},{"name":"Moody (HanseYachts) official","url":"https://moody-yachts.com/gb/sailing-yachts/moody-decksaloon-54/"}],"risks":["High systems complexity — reliance on electric winches/thrusters and their upkeep","Large saloon windows are an offshore heavy-weather exposure","Single spade rudder is less forgiving in groundings","Weaker independent community than Oyster/Tayana (mostly builder/dealer-centred)"],"scores":{"maintain":2,"simplicity":2,"parts":4,"community":2}}}$moodyds54$ AS j) s WHERE md5(j) = '5f3d23d58bafa53da2566bd03a7e4667') INSERT INTO public.boats SELECT (jsonb_populate_record(null::public.boats, j::jsonb || jsonb_build_object('created_at', now(), 'updated_at', now()))).* FROM ok ON CONFLICT (id) DO UPDATE SET id = excluded.id, name = excluded.name, builder = excluded.builder, designer = excluded.designer, color = excluded.color, years = excluded.years, material = excluded.material, category = excluded.category, cockpit_type = excluded.cockpit_type, loa = excluded.loa, lwl = excluded.lwl, beam = excluded.beam, draft_min = excluded.draft_min, draft_max = excluded.draft_max, displacement = excluded.displacement, ballast = excluded.ballast, ballast_ratio = excluded.ballast_ratio, sail_area = excluded.sail_area, air_draft = excluded.air_draft, engine = excluded.engine, drive = excluded.drive, cabins = excluded.cabins, keel = excluded.keel, cockpit = excluded.cockpit, fuel = excluded.fuel, water = excluded.water, loa_n = excluded.loa_n, lwl_ft = excluded.lwl_ft, beam_ft = excluded.beam_ft, disp_lb = excluded.disp_lb, draft_min_n = excluded.draft_min_n, sad = excluded.sad, dl = excluded.dl, fuel_n = excluded.fuel_n, water_n = excluded.water_n, engine_hp = excluded.engine_hp, price_min_usd = excluded.price_min_usd, price_max_usd = excluded.price_max_usd, budget = excluded.budget, budget_n = excluded.budget_n, best_for = excluded.best_for, protection_text = excluded.protection_text, rig = excluded.rig, handling_text = excluded.handling_text, engine_workshop = excluded.engine_workshop, systems = excluded.systems, storage_text = excluded.storage_text, range_text = excluded.range_text, accommodation = excluded.accommodation, high_lat_text = excluded.high_lat_text, tropical_text = excluded.tropical_text, price_text = excluded.price_text, price_new = excluded.price_new, price_used = excluded.price_used, budget_text = excluded.budget_text, notable = excluded.notable, scores = excluded.scores, tags = excluded.tags, fun = excluded.fun, price_examples = excluded.price_examples, sources = excluded.sources, youtube = excluded.youtube, pros = excluded.pros, cons = excluded.cons, awards = excluded.awards, endorsements = excluded.endorsements, badge = excluded.badge, own = excluded.own, updated_at = now() RETURNING id;

